+            repeat
+                if LocalRepairStatus.Get(ServiceItemLine."Repair Status Code") then
+                    if LocalRepairStatus.Priority < HighestPriority then begin
+                        HighestPriority := LocalRepairStatus.Priority;
+                        HighestPriorityRepairStatus := LocalRepairStatus;
+                    end;
+            until ServiceItemLine.Next() = 0;
+
+        if not FoundRepairStatus then
