+                ServHeader2."Finishing Time" := 0T;
+                ServHeader2."Service Time (Hours)" := 0;
+            end;
+            ServHeader2.UpdateServiceOrderChangeLog(ServHeader3);
+            ServHeader2.Modify();
+        end;
+    end;
